    @PostResource(path = "/exportUserWithTeam", requiredPermission = false)
    @Operation(summary = "export users with team")
    public void exportUserWithTeam(HttpServletRequest request, HttpServletResponse response) throws IOException {
        boolean checkedSuperManager = superManagerCacheService.checkSuperManager(SessionContext.getUserId());
        if(!checkedSuperManager)
            throw new BusinessException(AuthException.UNAUTHORIZED);
        setResponseHeader(request, response,"成员列表");
        List<ExportMemberWithTeamData> exampleDataList = new ArrayList<>();
        List<ExportUserVo> voList = userProjectQueryManager.exportUserWithTeam();
        voList.forEach(item -> {
            ExportMemberWithTeamData data = new ExportMemberWithTeamData();
            data.setTeamName(item.getTeamName());
            data.setParentTeamName(item.getParentTeamName());
            data.setEmail(item.getEmail());
            data.setUserNike(item.getUserNike());
            exampleDataList.add(data);
        });

        List<ExportMemberWithTeamData> viewList = userProjectQueryManager.exportViewUserWithTeam();


        ExcelWriter excelWriter = EasyExcel.write(response.getOutputStream())
                .excelType(ExcelTypeEnum.XLSX)
                .registerWriteHandler(new HeadBgColorFillHandle())
                .build();

        try {
            // 写入第一个sheet
            WriteSheet writeSheet1 = EasyExcel.writerSheet(0, "人员清单")
                    .head(ExportMemberWithTeamData.class)
                    .build();
            excelWriter.write(exampleDataList, writeSheet1);

            // 写入第二个sheet
            WriteSheet writeSheet2 = EasyExcel.writerSheet(1, "可见用户清单") // 或者其他你需要的sheet名称
                    .head(ExportMemberWithTeamData.class) // 如果第二个sheet用不同的数据结构，这里改成相应的class
                    .build();
            excelWriter.write(viewList, writeSheet2);

        } finally {
            // 写入异常关闭流
            if (excelWriter != null) {
                excelWriter.finish();
            }
        }
    }

