    //发送响应流方法
    public void setResponseHeader(HttpServletRequest request,HttpServletResponse response, String fileName) {
        try {
            response.setContentType("application/vnd.openxmlformats-officedocument.spreadsheetml.sheet");
            response.setCharacterEncoding("UTF-8");


            String userAgent = request.getHeader("User-Agent");
            String encodedFileName;

            if (userAgent != null && userAgent.contains("MSIE")) {
                // IE浏览器
                encodedFileName = URLEncoder.encode(fileName, StandardCharsets.UTF_8);
            } else if (userAgent != null && userAgent.contains("Firefox")) {
                // Firefox浏览器
                encodedFileName = new String(fileName.getBytes(StandardCharsets.UTF_8), "ISO8859-1");
            } else {
                // Chrome、Safari等现代浏览器
                encodedFileName = URLEncoder.encode(fileName, StandardCharsets.UTF_8).replaceAll("\\+", "%20");
            }

            response.setHeader("Content-Disposition",
                    "attachment;filename=\"" + encodedFileName + ".xlsx\"");

            // 缓存控制
            response.addHeader("Pragma", "no-cache");
            response.addHeader("Cache-Control", "no-cache");
        } catch (Exception ex) {
            log.error("Exception :",ex);
        }
    }

