package com.yottastudios.ns.collabspace.user.controller;

import com.yottastudios.ns.collabspace.auth.enums.AuthException;
import com.yottastudios.ns.collabspace.core.exception.BusinessException;
import com.yottastudios.ns.collabspace.core.support.ResponseData;
import com.yottastudios.ns.collabspace.shared.cache.service.SuperManagerCacheService;
import com.yottastudios.ns.collabspace.shared.component.scanner.annotation.ApiResource;
import com.yottastudios.ns.collabspace.shared.component.scanner.annotation.GetResource;
import com.yottastudios.ns.collabspace.shared.component.scanner.annotation.PostResource;
import com.yottastudios.ns.collabspace.shared.component.scanner.annotation.RequestRecord;
import com.yottastudios.ns.collabspace.shared.config.properties.ConstProperties;
import com.yottastudios.ns.collabspace.shared.constants.ParamsConstants;
import com.yottastudios.ns.collabspace.shared.context.SessionContext;
import com.yottastudios.ns.collabspace.user.dto.DataForInternalExportDto;
import com.yottastudios.ns.collabspace.user.entity.UserTeamEntity;
import com.yottastudios.ns.collabspace.user.enums.TeamDataSourceType;
import com.yottastudios.ns.collabspace.user.manager.query.UserManageQueryManager;
import com.yottastudios.ns.collabspace.user.manager.query.UserTeamQueryManager;
import com.yottastudios.ns.collabspace.user.manager.update.UserManageUpdateManager;
import com.yottastudios.ns.collabspace.user.manager.update.UserTeamUpdateManager;
import com.yottastudios.ns.collabspace.user.ro.*;
import com.yottastudios.ns.collabspace.user.vo.*;
import io.swagger.v3.oas.annotations.Hidden;
import io.swagger.v3.oas.annotations.Operation;
import io.swagger.v3.oas.annotations.Parameter;
import io.swagger.v3.oas.annotations.Parameters;
import io.swagger.v3.oas.annotations.enums.ParameterIn;
import io.swagger.v3.oas.annotations.media.Schema;
import io.swagger.v3.oas.annotations.tags.Tag;
import jakarta.annotation.Resource;
import jakarta.servlet.http.HttpServletResponse;
import jakarta.validation.Valid;
import lombok.extern.slf4j.Slf4j;
import org.apache.poi.xssf.usermodel.XSSFWorkbook;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.web.bind.annotation.PathVariable;
import org.springframework.web.bind.annotation.RequestBody;
import org.springframework.web.bind.annotation.RestController;

import java.io.BufferedOutputStream;
import java.io.ByteArrayOutputStream;
import java.io.IOException;
import java.io.OutputStream;
import java.net.URLEncoder;
import java.nio.charset.StandardCharsets;
import java.util.List;

/**
 * user interface.
 */
@Slf4j
@RestController
@Tag(name = "User Team")
@ApiResource(path = "/userTeam")
public class UserTeamController {

    @Resource
    private UserManageUpdateManager userManageUpdateManager;

    @Resource
    private UserManageQueryManager userManageQueryManager;

    @Resource
    private UserTeamQueryManager userTeamQueryManager;

    @Resource
    private UserTeamUpdateManager userTeamUpdateManager;

    @Resource
    private SuperManagerCacheService superManagerCacheService;
    @Resource
    private ConstProperties constProperties;

    @Value("${mm-test-only-tag:false}")
    private boolean mmTestOnlyOnlyTag;



    @PostResource(path = "/createTeam",requiredPermission = false)
    @Operation(summary = "Create Team")
    public ResponseData<TeamInfoVo> createTeam(@RequestBody @Valid TeamCreateRo ro) {
        Long userId = SessionContext.getUserId();
        //校验权限
        boolean checkedSuperManager = superManagerCacheService.checkSuperManager(userId);
        if(!checkedSuperManager)
            throw new BusinessException(AuthException.UNAUTHORIZED);

        if((constProperties.isInternalNetwork() || mmTestOnlyOnlyTag)&&!constProperties.isMirror()){
            ro.setDataSource(TeamDataSourceType.MANUAL.getId());
        }
        TeamInfoVo team = userTeamUpdateManager.createTeam(ro);

        return ResponseData.success(team);
    }

    @PostResource(path = "/updateTeam",requiredPermission = false, externalOnly = true)
    @Operation(summary = "Update Team")
    public ResponseData<TeamInfoVo> updateTeam(@RequestBody @Valid TeamUpdateRo ro) {
        Long userId = SessionContext.getUserId();
        //校验权限
        boolean checkedSuperManager = superManagerCacheService.checkSuperManager(userId);
        if(!checkedSuperManager)
            throw new BusinessException(AuthException.UNAUTHORIZED);

        TeamInfoVo team = userTeamUpdateManager.updateTeam(ro);
        return ResponseData.success(team);
    }

    @GetResource(path = "/deleteTeam/{teamId}",requiredPermission = false, externalOnly = true)
    @Operation(summary = "Delete Team")
    public ResponseData<Void> deleteTeam(@PathVariable Long teamId) {
        Long userId = SessionContext.getUserId();
        //校验权限
        boolean checkedSuperManager = superManagerCacheService.checkSuperManager(userId);
        if (!checkedSuperManager)
            throw new BusinessException(AuthException.UNAUTHORIZED);

        userTeamUpdateManager.deleteTeam(teamId);
        return ResponseData.success();

    }

    @PostResource(path = "/deleteAppTeam",requiredPermission = false, externalOnly = true)
    @Operation(summary = "Delete App Team")
    public ResponseData<Void> deleteAppTeam(@RequestBody AppTeamUserQueryRo ro) {
        Long userId = SessionContext.getUserId();

        userTeamUpdateManager.deleteAppTeam(ro);
        return ResponseData.success();

    }

    @PostResource(path = "/allUserListForTeam",requiredPermission = false)
    @Operation(summary = "All User List For Team")
    public ResponseData<List<UserInfoInTeamVo>> allUserCheckTeam(@RequestBody TeamQueryRo ro) {
        Long userId = SessionContext.getUserId();
        //校验权限
        boolean checkedSuperManager = superManagerCacheService.checkSuperManager(userId);
        if (!checkedSuperManager)
            throw new BusinessException(AuthException.UNAUTHORIZED);

        List<UserInfoInTeamVo> userInfoInTeamVos = userManageQueryManager.allUserCheckTeam(userId,ro.getTeamId());

        return ResponseData.success(userInfoInTeamVos);
    }

    @PostResource(path = "/getUserNicknameLike",requiredPermission = false)
    @Operation(summary = "Get User List Nickname Like For Team Manage")
    public ResponseData<List<UserInfoInTeamVo>> getUserNicknameLikeCheckTeam(@RequestBody @Valid UserSearchRo ro) {
        Long userId = SessionContext.getUserId();
        //校验权限
        boolean checkedSuperManager = superManagerCacheService.checkSuperManager(userId);
        if (!checkedSuperManager)
            throw new BusinessException(AuthException.UNAUTHORIZED);

        List<UserInfoInTeamVo> userInfoInTeamVos = userManageQueryManager.getUserNicknameLikeCheckTeam(ro.getTeamId(),ro.getNickName());

        return ResponseData.success(userInfoInTeamVos);

    }

    @PostResource(path = "/addUsersToTeams",requiredPermission = false, externalOnly = true)
    @Operation(summary = "Add Users To Teams")
    public ResponseData<Void> addUsersToTeams(@RequestBody @Valid UserTeamAddRo ro) {
        Long userId = SessionContext.getUserId();
        //校验权限
        boolean checkedSuperManager = superManagerCacheService.checkSuperManager(userId);
        if (!checkedSuperManager)
            throw new BusinessException(AuthException.UNAUTHORIZED);

        userManageUpdateManager.addUsersToTeams(ro);
        return ResponseData.success();
    }


    @PostResource(path = "/batchAddUserToTeams",requiredPermission = false)
    @Operation(summary = "Batch Add User To Teams")
    @RequestRecord(desc = "editUserTeam")
    public ResponseData<Void> batchAddUserToTeams(@RequestBody @Valid UserTeamAddBatchRo ro) {
        Long userId = SessionContext.getUserId();
        //校验权限
        boolean checkedSuperManager = superManagerCacheService.checkSuperManager(userId);
        if (!checkedSuperManager)
            throw new BusinessException(AuthException.UNAUTHORIZED);

        userManageUpdateManager.batchAddUserToTeams(ro);
        return ResponseData.success();
    }

    @PostResource(path = "/batchSetTeamLeadersInProject",requiredPermission = false, externalOnly = true)
    @Operation(summary = "Batch Set Users Team Leaders In Project")
    public ResponseData<Void> batchSetTeamLeadersInProject(@RequestBody @Valid UserTeamLeaderSetBatchRo ro) {
        Long userId = SessionContext.getUserId();
        //校验权限
        boolean checkedSuperManager = superManagerCacheService.checkSuperManager(userId);
        if (!checkedSuperManager)
            throw new BusinessException(AuthException.UNAUTHORIZED);

        userManageUpdateManager.batchSetUserTeamLeadersInProject(ro);
        return ResponseData.success();
    }

    @PostResource(path = "/setUsersTeamLeadersInProject",requiredPermission = false, externalOnly = true)
    @Operation(summary = "Set Users Team Leaders In Project")
    public ResponseData<Void> setUsersTeamLeadersInProject(@RequestBody @Valid UserTeamLeaderSetRo ro) {
        Long userId = SessionContext.getUserId();
        //校验权限
        boolean checkedSuperManager = superManagerCacheService.checkSuperManager(userId);
        if (!checkedSuperManager)
            throw new BusinessException(AuthException.UNAUTHORIZED);

        userManageUpdateManager.setUsersTeamLeadersInProject(ro);
        return ResponseData.success();
    }

    @GetResource(path = "/getTeamInfo/{teamId}",requiredPermission = false)
    @Operation(summary = "Get Team Info")
    public ResponseData<TeamInfoVo> getTeamInfo(@PathVariable Long teamId) {
        Long userId = SessionContext.getUserId();
        //校验权限
        boolean checkedSuperManager = superManagerCacheService.checkSuperManager(userId);
        if (!checkedSuperManager)
            throw new BusinessException(AuthException.UNAUTHORIZED);

        TeamInfoVo teamInfo = userTeamQueryManager.getTeamInfo(teamId);
        return ResponseData.success(teamInfo);
    }

    @GetResource(path = "/listTeamUsers/{teamId}",requiredPermission = false)
    @Operation(summary = "Get Team Info With User")
    public ResponseData<TeamInfoWithUserVo> listTeamUsers(@PathVariable Long teamId) {
        Long userId = SessionContext.getUserId();
        //校验权限
        boolean checkedSuperManager = superManagerCacheService.checkSuperManager(userId);
        if (!checkedSuperManager)
            throw new BusinessException(AuthException.UNAUTHORIZED);

        TeamInfoWithUserVo teamInfoWithUserVo = userTeamQueryManager.listTeamUsers(teamId);
        return ResponseData.success(teamInfoWithUserVo);
    }

    @GetResource(path = "/getTeamNameLike/{name}",requiredPermission = false)
    @Operation(summary = "Get Team Name Like")
    public ResponseData<List<TeamInfoWithProjectVo>> getTeamNameLike(@PathVariable String name) {
        Long userId = SessionContext.getUserId();
        //校验权限
        boolean checkedSuperManager = superManagerCacheService.checkSuperManager(userId);
        if (!checkedSuperManager)
            throw new BusinessException(AuthException.UNAUTHORIZED);

        List<TeamInfoWithProjectVo> teamNameLike = userTeamQueryManager.getTeamNameLike(name);
        return ResponseData.success(teamNameLike);
    }


    @GetResource(path = "/getTeamOfLeader/{isCommon}",requiredPermission = false)
    @Operation(summary = "Get Team of Leader")
    public ResponseData<List<TeamInfoWithProjectVo>> getTeamOfLeader(@PathVariable Boolean isCommon) {
        Long userId = SessionContext.getUserId();

        List<TeamInfoWithProjectVo> teamOfLeader = userTeamQueryManager.getTeamOfLeader(userId, isCommon);

        return ResponseData.success(teamOfLeader);

    }

    @GetResource(path = "/getTeamOfSpace/{spaceId}",requiredPermission = false)
    @Operation(summary = "Get Team of Space")
    public ResponseData<List<AppTeamInfoWithSpaceVo>> getTeamOfSpace(@PathVariable String spaceId) {
        Long userId = SessionContext.getUserId();

        List<AppTeamInfoWithSpaceVo> teamOfSpace = userTeamQueryManager.getTeamOfSpace(userId,spaceId);

        return ResponseData.success(teamOfSpace);

    }

    @PostResource(path = "/bindAppTeams",requiredPermission = false, externalOnly = true)
    @Parameters({
            @Parameter(name = ParamsConstants.SPACE_ID, description = "space id", required = true,
                    schema = @Schema(type = "string"), in = ParameterIn.HEADER, example = "spcVyED5StRev"),
    })
    @Operation(summary = "Bind App Teams")
    public ResponseData<Void> bindAppTeams(@RequestBody @Valid AppTeamBatchBindRo ro) {
        Long userId = SessionContext.getUserId();
        //校验权限
        boolean checkedSuperManager = superManagerCacheService.checkSuperManager(userId);
        if (!checkedSuperManager)
            throw new BusinessException(AuthException.UNAUTHORIZED);

        userTeamUpdateManager.bindAppTeamsBatch(ro,userId);

        return ResponseData.success();
    }

    @PostResource(path = "/getAppTeamUser",requiredPermission = false)
    @Operation(summary = "Get App Team User")
    public ResponseData<List<UserSimpleInfoVo>> getAppTeamUser(@RequestBody @Valid AppTeamUserQueryRo ro) {
        Long userId = SessionContext.getUserId();

        List<UserSimpleInfoVo> teamUser = userTeamQueryManager.getAppTeamUser(ro);
        return ResponseData.success(teamUser);
    }

    @PostResource(path = "/createAppTeamsWithBind",requiredSpaceAdmin = true)
    @Operation(summary = "createAppTeamsWithBind")
    public ResponseData<Void> createAppTeamsWithBind(@RequestBody @Valid AppTeamBindCreateBatchRo ro) {
          Long userId = SessionContext.getUserId();
//        //校验权限
//        boolean checkedSuperManager = superManagerCacheService.checkSuperManager(userId);
//        if (!checkedSuperManager)
//            throw new BusinessException(AuthException.UNAUTHORIZED);

        userTeamUpdateManager.createAppTeamsWithBind(ro,userId);


        return ResponseData.success();
    }

    @PostResource(path = "/queryBindInfoByAppTeams",requiredPermission = false)
    @Operation(summary = "Query Bind Info By App Teams")
    public ResponseData<List<AppTeamBindInfoQueryVo>> queryBindInfoByAppTeams(@RequestBody @Valid AppTeamBindInfoQueryRo ro) {

        Long userId = SessionContext.getUserId();
        List<AppTeamBindInfoQueryVo> appTeamBindInfoQueryVos = userTeamQueryManager.queryBindInfoByAppTeams(ro, userId);
        return ResponseData.success(appTeamBindInfoQueryVos);

    }

    @PostResource(path = "/setTeamManagerByEmails",requiredPermission = false)
    @Operation(summary = "Set Team Manager By Emails")
    @RequestRecord(desc = "setTeamViewer")
    public ResponseData<Void> setTeamManagerByEmails(@RequestBody @Valid UserTeamLeaderEmailRo ro) {
        Long userId = SessionContext.getUserId();
        //校验权限
        boolean checkedSuperManager = superManagerCacheService.checkSuperManager(userId);
        if (!checkedSuperManager)
            throw new BusinessException(AuthException.UNAUTHORIZED);

        userManageUpdateManager.setTeamManagerByEmails(ro);
        return ResponseData.success();
    }

    @PostResource(path = "/delTeamManager",requiredPermission = false)
    @Operation(summary = "Del Team Manager")
    @RequestRecord(desc = "delTeamViewer")
    public ResponseData<Void> delTeamManager(@RequestBody @Valid UserTeamLeaderEmailRo ro) {
        Long userId = SessionContext.getUserId();
        //校验权限
        boolean checkedSuperManager = superManagerCacheService.checkSuperManager(userId);
        if (!checkedSuperManager)
            throw new BusinessException(AuthException.UNAUTHORIZED);

        userManageUpdateManager.delTeamManager(ro);
        return ResponseData.success();
    }

    @GetResource(path = "/gerTeamManagerList",requiredPermission = false)
    @Operation(summary = "Get Team Manager List")
    public ResponseData<List<TeamManagerListVo>> gerTeamManagerList(TeamManagerListRo ro) {
        Long userId = SessionContext.getUserId();
        //校验权限
        boolean checkedSuperManager = superManagerCacheService.checkSuperManager(userId);
        if (!checkedSuperManager)
            throw new BusinessException(AuthException.UNAUTHORIZED);

        List<TeamManagerListVo> list = userManageUpdateManager.gerTeamManagerList(ro);
        return ResponseData.success(list);
    }

    @Hidden
    @GetResource(path = "/updateMemberBindTag",requiredLogin = false, requiredPermission = false)
    public ResponseData<Void> updateMemberBindTag() {
        userTeamUpdateManager.updateMemberBindTag();
        return ResponseData.success();
    }

    @Hidden
    @GetResource(path = "/dealHistoryViewData",requiredLogin = false, requiredPermission = false)
    public ResponseData<Void> dealHistoryViewData() {
        userTeamUpdateManager.dealHistoryViewData();
        return ResponseData.success();
    }



    @GetResource(path = "/exportInternalUserManageDataToExcel",requiredPermission = false)
    public void exportInternalUserManageDataToExcel(HttpServletResponse response) {


        String filename="人员管理后台_内网.xlsx";

        DataForInternalExportDto data = userManageQueryManager.allUserListForInternalExport();

        try {

            XSSFWorkbook workbook = userManageQueryManager.exportUserManageDataToExcel(data);
            ByteArrayOutputStream outputStream = new ByteArrayOutputStream();
            workbook.write(outputStream);
            workbook.close();

            response.reset();
            response.setHeader("Content-Disposition", "attachment;filename=" +  URLEncoder.encode(filename, StandardCharsets.UTF_8));
            response.setContentType("application/octet-stream;charset=ISO8859-1");


            OutputStream toClient = new BufferedOutputStream(response.getOutputStream());
            toClient.write(outputStream.toByteArray());
            toClient.flush();
            toClient.close();

        } catch (IOException ex) {
            log.error("Error while compressing response: ", ex);
        }


    }

    @Hidden
    @GetResource(path = "/updateDateSource",requiredLogin = false, requiredPermission = false)
    public ResponseData<Void> updateDateSource() {

        userTeamUpdateManager.updateDateSource();
        return ResponseData.success();
    }

    @Hidden
    @GetResource(path = "/listTeam",requiredLogin = false, requiredPermission = false)
    public ResponseData<List<UserTeamEntity>> recoverUser() {

        List<UserTeamEntity> userTeamEntities = userTeamUpdateManager.listTeam();

        return ResponseData.success(userTeamEntities);
    }



}

