package com.yottastudios.ns.collabspace.user.vo;

import com.collabspace.integration.grpc.UserInfo;
import com.fasterxml.jackson.databind.annotation.JsonSerialize;
import com.yottastudios.ns.collabspace.shared.support.serializer.LongToStringSerializer;
import io.swagger.v3.oas.annotations.media.Schema;
import lombok.AllArgsConstructor;
import lombok.Builder;
import lombok.Data;
import lombok.NoArgsConstructor;

import java.io.Serializable;

@Data
@Builder(toBuilder = true)
@NoArgsConstructor
@AllArgsConstructor
@Schema(name = "UserSimpleInfoVo")
public class UserSimpleInfoVo implements Serializable {

    private static final long serialVersionUID = 1L;

    /**
     * Primary Key.
     */
    @JsonSerialize(using = LongToStringSerializer.class)
    private Long id;

    /**
     * User ID.
     */
    private String uuid;

    /**
     * Nick Name.
     */
    @Schema(description = "nickName")
    private String nickName;

    /**
     * Email.
     */
    private String email;

    /**
     * 用户状态(0:正常,1:禁用).
     */
    @Schema(description = "用户状态(0:正常,1:禁用)")
    private Integer status;

    private Boolean isPaused;

    private String avatar;

    /**
     * 是否为外派
     */
    @Schema(description = "是否为外派")
    private Boolean isExpat;

    @Schema(description = "是否同步mm,false即手动添加; 外网默认false且字段无意义")
    private Boolean isMmSync;

    public UserSimpleInfoVo(UserInfo userInfo) {
        this.uuid = userInfo.getUuid();
        this.nickName = userInfo.getNickName();
        this.email = userInfo.getEmail();
        this.status = userInfo.getStatus();
        this.isPaused = userInfo.getIsPaused();
        this.id = userInfo.getId();
        this.avatar=userInfo.getAvatar();
        this.isExpat = userInfo.getIsExpat();
        this.isMmSync = userInfo.getIsMmSync();
    }

}

