import com.yottastudios.ns.collabspace.user.manager.query.UserManageQueryManager;
import com.yottastudios.ns.collabspace.user.service.*;
import com.yottastudios.ns.collabspace.user.vo.TeamInfoByUserVo;
import com.yottastudios.ns.collabspace.user.vo.UserInfoForManageVo;
import com.yottastudios.ns.collabspace.user.vo.UserInfoInTeamVo;
import com.yottastudios.ns.collabspace.user.vo.UserSimpleInfoVo;
import jakarta.annotation.Resource;
import lombok.extern.slf4j.Slf4j;
import org.apache.commons.collections4.CollectionUtils;
import org.apache.poi.ooxml.POIXMLProperties;
import org.apache.poi.openxml4j.exceptions.InvalidFormatException;
