  const r1 = await POST('/internal/user/checkExist', { email: CONFIG.existUser.email });
  assert('§11.无token - code非500', r1.code !== 500, r1.code);

  // 参数为空 → 错误码不应是 500
  const r2 = await authPOST('/internal/user/checkExist', {});
  assert('§11.空参数 - code非500', r2.code !== 500, r2.code);

  // 正常请求不存在用户 → success=true, exist=false
  const r3 = await authPOST('/internal/user/checkExist', { email: CONFIG.fakeUser.email });
  assert('§11.不存在用户 - success=true（查询本身成功）', r3.success === true, r3);
  assert('§11.不存在用户 - exist=false', r3.data?.exist === false, r3.data);
}

async function test_§12_免登录验证() {
  console.log('\n🔓 §12. 免登录验证（requiredLogin=false）');

  // 不带任何 cookie/session，只带 token → 应该能正常调用
  const r1 = await authPOST('/internal/user/checkExist', { email: CONFIG.existUser.email });
  assert('§12.无session+有token - success=true', r1.success === true, r1);
  assert('§12.无session+有token - exist=true', r1.data?.exist === true, r1.data);

  // 带错误 session + 正确 token → 也应该能正常调用
  const r2 = await POST('/internal/user/checkExist', { email: CONFIG.existUser.email }, {
    'X-Internal-Token': CONFIG.internalToken,
    'Cookie': 'SESSION=invalid-session-id',
  });
  assert('§12.错误session+有token - success=true', r2.success === true, r2);
}

async function test_§13_请求体异常() {
  console.log('\n💥 §13. 请求体异常');

  // 空 body
  const r1 = await fetch(`${CONFIG.host}/api/v1/internal/user/checkExist`, {
    method: 'POST',
    headers: {
      'content-type': 'application/json',
      'X-Internal-Token': CONFIG.internalToken,
    },
    body: '',
  });
  assert('§13.空body - 不报500', r1.status !== 500, r1.status);

  // 非 JSON body
  const r2 = await fetch(`${CONFIG.host}/api/v1/internal/user/checkExist`, {
    method: 'POST',
    headers: {
      'content-type': 'application/json',
      'X-Internal-Token': CONFIG.internalToken,
    },
    body: 'not json',
  });
  assert('§13.非JSON body - 不报500', r2.status !== 500, r2.status);

  // content-type 不是 json
  const r3 = await fetch(`${CONFIG.host}/api/v1/internal/user/checkExist`, {
    method: 'POST',
    headers: {
      'content-type': 'text/plain',
      'X-Internal-Token': CONFIG.internalToken,
    },
    body: JSON.stringify({ email: CONFIG.existUser.email }),
  });
  assert('§13.content-type=text/plain - 不报500', r3.status !== 500, r3.status);

  // GET 方法（接口只支持 POST）
  const r4 = await fetch(`${CONFIG.host}/api/v1/internal/user/checkExist`, {
    method: 'GET',
    headers: { 'X-Internal-Token': CONFIG.internalToken },
  });
  assert('§13.GET方法 - 不报500', r4.status !== 500, r4.status);
}

