package com.yottastudios.ns.collabspace.user.controller;

import com.yottastudios.ns.collabspace.core.support.ResponseData;
import com.yottastudios.ns.collabspace.grpc.IApitableGrpcClientService;
import com.yottastudios.ns.collabspace.shared.component.scanner.annotation.ApiResource;
import com.yottastudios.ns.collabspace.shared.component.scanner.annotation.PostResource;
import com.yottastudios.ns.collabspace.shared.config.properties.ConstProperties;
import com.yottastudios.ns.collabspace.user.ro.InternalUserCheckExistRo;
import com.yottastudios.ns.collabspace.user.vo.InternalUserCheckExistVo;
import com.yottastudios.ns.collabspace.user.vo.UserSimpleInfoVo;
import io.swagger.v3.oas.annotations.Operation;
import io.swagger.v3.oas.annotations.tags.Tag;
import jakarta.annotation.Resource;
import jakarta.servlet.http.HttpServletRequest;
import lombok.extern.slf4j.Slf4j;
import org.apache.commons.lang3.StringUtils;
import org.springframework.web.bind.annotation.RequestBody;
import org.springframework.web.bind.annotation.RestController;

import java.util.List;

/**
 * 内部接口 - 供其他系统查询成员数据
 * 需要在请求头中携带 X-Internal-Token 进行服务间鉴权
 */
@Slf4j
@RestController
@Tag(name = "InternalUser")
@ApiResource(path = "/internal/user")
public class InternalUserController {

    private static final String INTERNAL_TOKEN_HEADER = "X-Internal-Token";

    @Resource
    private IApitableGrpcClientService apitableGrpcClientService;

    @Resource
    private ConstProperties constProperties;

    /**
     * 检查用户是否存在（花名/邮箱至少传一个，精确匹配）
     */
    @PostResource(path = "/checkExist", requiredLogin = false, requiredPermission = false)
    @Operation(summary = "检查用户是否存在（内部接口）")
    public ResponseData<?> checkUserExist(HttpServletRequest request,
                                                                  @RequestBody InternalUserCheckExistRo ro) {
        // 服务间 token 鉴权
        if (!validateInternalToken(request)) {
            log.warn("[lbl][2184-examUser][InternalUser][AUTH] 鉴权失败, ip={}", request.getRemoteAddr());
            return ResponseData.error("Unauthorized");
        }

        String nickName = ro.getNickName();
        String email = ro.getEmail();
        log.info("[lbl][2184-examUser][InternalUser][QUERY] 检查用户是否存在, nickName={}, email={}, ip={}", nickName, email, request.getRemoteAddr());

        if (StringUtils.isBlank(nickName) && StringUtils.isBlank(email)) {
            log.warn("[lbl][2184-examUser][InternalUser][QUERY] 参数校验失败, nickName和email均为空");
            return ResponseData.error("nickName 和 email 至少传一个");
        }

        // 优先按邮箱精确查询（效率更高）
        if (StringUtils.isNotBlank(email)) {
            UserSimpleInfoVo user = apitableGrpcClientService.getUserByEmail(email);
            if (user != null) {
                // 如果同时传了花名，需要双重校验
                if (StringUtils.isNotBlank(nickName) && !nickName.equals(user.getNickName())) {
                    log.info("[lbl][2184-examUser][InternalUser][QUERY] 邮箱匹配但花名不匹配, email={}, reqNickName={}, actualNickName={}", email, nickName, user.getNickName());
                    return ResponseData.success(InternalUserCheckExistVo.builder().exist(false).build());
                }
                log.info("[lbl][2184-examUser][InternalUser][QUERY] 用户存在, email={}, nickName={}, status={}", user.getEmail(), user.getNickName(), user.getStatus());
                return ResponseData.success(buildExistVo(user));
            }
            log.info("[lbl][2184-examUser][InternalUser][QUERY] 用户不存在, email={}", email);
            return ResponseData.success(InternalUserCheckExistVo.builder().exist(false).build());
        }

        // 仅按花名查询：先模糊查，再精确过滤
        List<UserSimpleInfoVo> users;
        try {
            users = apitableGrpcClientService.getUsersLikeNickname(nickName);
        } catch (Exception e) {
            log.error("[lbl][2184-examUser][InternalUser][QUERY] gRPC花名查询异常, nickName={}, error={}", nickName, e.getMessage(), e);
            return ResponseData.success(InternalUserCheckExistVo.builder().exist(false).build());
        }

        UserSimpleInfoVo matched = users.stream()
                .filter(u -> nickName.equals(u.getNickName()))
                .findFirst()
                .orElse(null);

        if (matched != null) {
            log.info("[lbl][2184-examUser][InternalUser][QUERY] 用户存在, nickName={}, email={}, status={}", matched.getNickName(), matched.getEmail(), matched.getStatus());
            return ResponseData.success(buildExistVo(matched));
        }
        log.info("[lbl][2184-examUser][InternalUser][QUERY] 用户不存在, nickName={}", nickName);
        return ResponseData.success(InternalUserCheckExistVo.builder().exist(false).build());
    }

    /**
     * 校验内部接口 token
     */
    private boolean validateInternalToken(HttpServletRequest request) {
        String configuredToken = constProperties.getInternalApiToken();
        if (StringUtils.isBlank(configuredToken)) {
            log.error("[lbl][2184-examUser][InternalUser][AUTH] internal-api-token 未配置，拒绝所有请求");
            return false;
        }
        String requestToken = request.getHeader(INTERNAL_TOKEN_HEADER);
        return configuredToken.equals(requestToken);
    }

    private InternalUserCheckExistVo buildExistVo(UserSimpleInfoVo user) {
        return InternalUserCheckExistVo.builder()
                .exist(true)
                .nickName(user.getNickName())
                .email(user.getEmail())
                .status(user.getStatus())
                .build();
    }
}

