/**
 * 2184-用户检查给exam - 接口测试脚本
 *
 * 用法: node test-api.js
 * 要求: Node.js 18+（原生 fetch）
 * 测试接口: POST /api/v1/internal/user/checkExist
 */

// ========== 配置 ==========
const CONFIG = {
  host: 'http://xcollabspace-test.xtool-staging.yottastudios.com',
  internalToken: 'da08c2a0256e4072ecd5f5daed1e04dfbdfd081b7bcd53ae4eab874aebce9414',
  // 真实存在的用户（status=0 正常）
  existUser: {
    nickName: '翁斯坦',
    email: 'wengsitan@yottastudios.com',
  },
  // 真实存在的用户2（用于花名查询，需 status=0 且 gRPC 可查到）
  existUser2: {
    nickName: 'bike',
    email: 'bike@yottastudios.com',
  },
  // 不存在的用户
  fakeUser: {
    nickName: '绝对不存在的花名XYZ999',
    email: 'absolutely_not_exist_xyz999@yottastudios.com',
  },
};

// ========== 测试框架 ==========
let passed = 0;
let failed = 0;

function assert(name, condition, detail) {
  if (condition) {
    console.log(`  ✅ ${name}`);
    passed++;
  } else {
    console.log(`  ❌ ${name}`);
    if (detail !== undefined)
      console.log(`     实际值:`, typeof detail === 'object'
        ? JSON.stringify(detail).slice(0, 300) : detail);
    failed++;
  }
}

// ========== HTTP 工具 ==========
async function POST(path, body, headers = {}) {
  const opts = {
    method: 'POST',
    headers: {
      'content-type': 'application/json',
      ...headers,
    },
    body: JSON.stringify(body),
  };
  const res = await fetch(`${CONFIG.host}/api/v1${path}`, opts);
  return res.json();
}

async function rawPOST(path, body, headers = {}) {
  const opts = {
    method: 'POST',
    headers: {
      'content-type': 'application/json',
      ...headers,
    },
    body: JSON.stringify(body),
  };
  return fetch(`${CONFIG.host}/api/v1${path}`, opts);
}

/** 带 token 的 POST */
async function authPOST(path, body) {
  return POST(path, body, { 'X-Internal-Token': CONFIG.internalToken });
}

