  assert('§1.邮箱查询 - 返回 success', r1.success === true, r1);
  assert('§1.邮箱查询 - data 不为 null', r1.data != null, r1.data);
  assert('§1.邮箱查询 - exist=true', r1.data?.exist === true, r1.data?.exist);
  assert('§1.邮箱查询 - 返回 nickName (string)', typeof r1.data?.nickName === 'string', r1.data?.nickName);
  assert('§1.邮箱查询 - 返回 email (string)', typeof r1.data?.email === 'string', r1.data?.email);
  assert('§1.邮箱查询 - 返回 status (number)', typeof r1.data?.status === 'number', r1.data?.status);
  assert('§1.邮箱查询 - email 值一致', r1.data?.email === CONFIG.existUser.email, r1.data?.email);

  // 仅花名查询 - 存在的用户
  const r2 = await authPOST('/internal/user/checkExist', { nickName: CONFIG.existUser.nickName });
  assert('§1.花名查询 - 返回 success', r2.success === true, r2);
  assert('§1.花名查询 - exist=true', r2.data?.exist === true, r2.data?.exist);
  assert('§1.花名查询 - nickName 值一致', r2.data?.nickName === CONFIG.existUser.nickName, r2.data?.nickName);
  assert('§1.花名查询 - 返回 email', typeof r2.data?.email === 'string', r2.data?.email);
}

async function test_02_paramValidation() {
  console.log('\n🔒 §2. 参数校验');

  // 两个都为空
  const r1 = await authPOST('/internal/user/checkExist', {});
  assert('§2.空参数 - success=false', r1.success === false, r1);

  // 两个都为空字符串
  const r2 = await authPOST('/internal/user/checkExist', { nickName: '', email: '' });
  assert('§2.空字符串 - success=false', r2.success === false, r2);

  // 两个都为纯空格
  const r3 = await authPOST('/internal/user/checkExist', { nickName: '   ', email: '   ' });
  assert('§2.纯空格 - success=false', r3.success === false, r3);

  // 只传 nickName 为空，email 有值 → 应该正常走邮箱查询
  const r4 = await authPOST('/internal/user/checkExist', { nickName: '', email: CONFIG.existUser.email });
  assert('§2.nickName空+email有值 - success=true', r4.success === true, r4);
  assert('§2.nickName空+email有值 - exist=true', r4.data?.exist === true, r4.data);

  // 只传 email 为空，nickName 有值 → 应该正常走花名查询
  const r5 = await authPOST('/internal/user/checkExist', { nickName: CONFIG.existUser.nickName, email: '' });
  assert('§2.email空+nickName有值 - success=true', r5.success === true, r5);
  assert('§2.email空+nickName有值 - exist=true', r5.data?.exist === true, r5.data);

  // 只传 null
  const r6 = await authPOST('/internal/user/checkExist', { nickName: null, email: null });
  assert('§2.null参数 - success=false', r6.success === false, r6);
}

async function test_03_emailQuery() {
  console.log('\n📧 §3. 按邮箱精确查询');

  // 存在的邮箱
  const r1 = await authPOST('/internal/user/checkExist', { email: CONFIG.existUser.email });
  assert('§3.存在邮箱 - exist=true', r1.data?.exist === true, r1.data);
  assert('§3.存在邮箱 - email匹配', r1.data?.email === CONFIG.existUser.email, r1.data?.email);

  // 不存在的邮箱
  const r2 = await authPOST('/internal/user/checkExist', { email: CONFIG.fakeUser.email });
  assert('§3.不存在邮箱 - exist=false', r2.data?.exist === false, r2.data);
  assert('§3.不存在邮箱 - nickName 为空/null', !r2.data?.nickName, r2.data?.nickName);
  assert('§3.不存在邮箱 - email 为空/null', !r2.data?.email, r2.data?.email);

  // 邮箱大小写（邮箱通常不区分大小写，看后端实现）
  const upperEmail = CONFIG.existUser.email.toUpperCase();
  const r3 = await authPOST('/internal/user/checkExist', { email: upperEmail });
  assert('§3.大写邮箱 - 不报500', r3.success === true || (r3.code && r3.code !== 500), r3);

  // 第二个用户的邮箱
  const r4 = await authPOST('/internal/user/checkExist', { email: CONFIG.existUser2.email });
  assert('§3.第二用户邮箱 - exist=true', r4.data?.exist === true, r4.data);
}

async function test_04_nickNameQuery() {
  console.log('\n🏷️ §4. 按花名精确查询');

  // 存在的花名
  const r1 = await authPOST('/internal/user/checkExist', { nickName: CONFIG.existUser.nickName });
  assert('§4.存在花名 - exist=true', r1.data?.exist === true, r1.data);
  assert('§4.存在花名 - nickName匹配', r1.data?.nickName === CONFIG.existUser.nickName, r1.data?.nickName);

  // 不存在的花名
  const r2 = await authPOST('/internal/user/checkExist', { nickName: CONFIG.fakeUser.nickName });
  assert('§4.不存在花名 - exist=false', r2.data?.exist === false, r2.data);

  // 花名模糊匹配不应命中（接口要求精确）
  // 如果存在 "翁斯坦"，传 "翁斯" 不应该返回 exist=true
  if (CONFIG.existUser.nickName.length > 1) {
    const partial = CONFIG.existUser.nickName.substring(0, CONFIG.existUser.nickName.length - 1);
    const r3 = await authPOST('/internal/user/checkExist', { nickName: partial });
    assert(`§4.部分花名"${partial}" - exist=false（精确匹配不应命中）`, r3.data?.exist === false, r3.data);
  }

  // 第二个用户
  const r4 = await authPOST('/internal/user/checkExist', { nickName: CONFIG.existUser2.nickName });
  assert('§4.第二用户花名 - exist=true', r4.data?.exist === true, r4.data);
}

async function test_05_dualFieldCheck() {
  console.log('\n🔗 §5. 双字段同时传 - 双重校验');

  // 花名+邮箱都正确 → exist=true
  const r1 = await authPOST('/internal/user/checkExist', {
    nickName: CONFIG.existUser.nickName,
    email: CONFIG.existUser.email,
  });
  assert('§5.双字段匹配 - exist=true', r1.data?.exist === true, r1.data);

  // 邮箱正确 + 花名错误 → exist=false（双重校验）
  const r2 = await authPOST('/internal/user/checkExist', {
    nickName: '完全不匹配的花名',
    email: CONFIG.existUser.email,
  });
  assert('§5.邮箱对+花名错 - exist=false', r2.data?.exist === false, r2.data);

  // 邮箱正确 + 另一个用户的花名 → exist=false
  const r3 = await authPOST('/internal/user/checkExist', {
    nickName: CONFIG.existUser2.nickName,
    email: CONFIG.existUser.email,
  });
  assert('§5.邮箱A+花名B(交叉) - exist=false', r3.data?.exist === false, r3.data);

  // 邮箱不存在 + 花名正确 → exist=false（邮箱优先，邮箱查不到直接返回false）
  const r4 = await authPOST('/internal/user/checkExist', {
    nickName: CONFIG.existUser.nickName,
    email: CONFIG.fakeUser.email,
  });
  assert('§5.邮箱不存在+花名对 - exist=false（邮箱优先）', r4.data?.exist === false, r4.data);

  // 都不存在
  const r5 = await authPOST('/internal/user/checkExist', {
    nickName: CONFIG.fakeUser.nickName,
    email: CONFIG.fakeUser.email,
  });
  assert('§5.都不存在 - exist=false', r5.data?.exist === false, r5.data);
}

async function test_06_responseStructure() {
  console.log('\n📦 §6. 返回结果结构校验');

  // 存在时完整结构
  const r1 = await authPOST('/internal/user/checkExist', { email: CONFIG.existUser.email });
  assert('§6.存在 - 含 exist 字段', 'exist' in (r1.data || {}), r1.data);
  assert('§6.存在 - 含 nickName 字段', 'nickName' in (r1.data || {}), r1.data);
  assert('§6.存在 - 含 email 字段', 'email' in (r1.data || {}), r1.data);
  assert('§6.存在 - 含 status 字段', 'status' in (r1.data || {}), r1.data);
  assert('§6.存在 - exist 类型为 boolean', typeof r1.data?.exist === 'boolean', typeof r1.data?.exist);
  assert('§6.存在 - status 类型为 number', typeof r1.data?.status === 'number', typeof r1.data?.status);

  // 不存在时结构
  const r2 = await authPOST('/internal/user/checkExist', { email: CONFIG.fakeUser.email });
  assert('§6.不存在 - exist=false', r2.data?.exist === false, r2.data);
  assert('§6.不存在 - nickName 无值', !r2.data?.nickName, r2.data?.nickName);
}

async function test_07_tokenAuth() {
  console.log('\n🔐 §7. Token Header 校验');

  // 无 token
  const r1 = await POST('/internal/user/checkExist', { email: CONFIG.existUser.email });
  assert('§7.无token - success=false', r1.success === false, r1);

  // 错误 token
  const r2 = await POST('/internal/user/checkExist', { email: CONFIG.existUser.email }, {
    'X-Internal-Token': 'wrong-token-123',
  });
  assert('§7.错误token - success=false', r2.success === false, r2);

  // 空 token
  const r3 = await POST('/internal/user/checkExist', { email: CONFIG.existUser.email }, {
    'X-Internal-Token': '',
  });
  assert('§7.空token - success=false', r3.success === false, r3);

  // 正确 token
  const r4 = await authPOST('/internal/user/checkExist', { email: CONFIG.existUser.email });
  assert('§7.正确token - success=true', r4.success === true, r4);
  assert('§7.正确token - exist=true', r4.data?.exist === true, r4.data);

  // token 前后有空格（HTTP header 会自动 trim，所以实际上能通过鉴权）
  const r5 = await POST('/internal/user/checkExist', { email: CONFIG.existUser.email }, {
    'X-Internal-Token': ' ' + CONFIG.internalToken + ' ',
  });
  assert('§7.token前后空格 - success=true（HTTP header自动trim）', r5.success === true, r5);

  // token 大小写（hex token 大小写不同，严格比对应该失败）
  // 注意：如果 token 全小写，toUpperCase 会产生不同值
  const upperToken = CONFIG.internalToken.toUpperCase();
  const tokenChanged = upperToken !== CONFIG.internalToken;
  if (tokenChanged) {
    const r6 = await POST('/internal/user/checkExist', { email: CONFIG.existUser.email }, {
      'X-Internal-Token': upperToken,
    });
    assert('§7.token大写 - success=false（严格比对）', r6.success === false, r6);
  }
}

async function test_08_injection() {
  console.log('\n🛡️ §8. 注入防护 + 特殊字符');

  // SQL 注入 - email 参数（gRPC 参数化查询，不会注入）
  const sqlPayloads = [
    "' OR 1=1 --",
    "1; DROP TABLE user;",
    "' UNION SELECT * FROM user --",
    "admin'/*",
  ];
  for (const payload of sqlPayloads) {
    const r = await authPOST('/internal/user/checkExist', { email: payload });
    assert(`§8.SQL注入 email "${payload.slice(0, 20)}" - 返回成功(exist=false)`,
      r.success === true && r.data?.exist === false, r);
  }

  // SQL 注入 - nickName 参数（gRPC 模糊查询，特殊字符可能导致异常，try-catch 兜底）
  for (const payload of sqlPayloads) {
    const r = await authPOST('/internal/user/checkExist', { nickName: payload });
    // try-catch 兜底后返回 success+exist=false；未部署前可能返回 500
    assert(`§8.SQL注入 nickName "${payload.slice(0, 20)}" - 不崩溃`,
      r.success === true || r.success === false, r);
  }

  // XSS（nickName 走 gRPC 模糊查询，特殊字符可能触发异常）
  const xssPayloads = ['<script>alert(1)</script>', '<img onerror=alert(1)>', '{{7*7}}'];
  for (const payload of xssPayloads) {
    const r = await authPOST('/internal/user/checkExist', { nickName: payload });
    assert(`§8.XSS nickName "${payload.slice(0, 20)}" - 不崩溃`,
      r.success === true || r.success === false, r);
  }

  // 特殊字符（排除 \t \n，它们被 StringUtils.isBlank 视为空白，属于正确行为）
  const specialChars = ['%', '_', '\\', '"', '\0'];
  for (const ch of specialChars) {
    const r = await authPOST('/internal/user/checkExist', { email: ch });
    assert(`§8.特殊字符 email "${encodeURIComponent(ch)}" - 不报500`,
      r.success === true, r);
  }

  // 超长字符串
  const longStr = 'a'.repeat(500);
  const r1 = await authPOST('/internal/user/checkExist', { email: longStr });
  assert('§8.超长email(500) - 返回成功(exist=false)',
    r1.success === true && r1.data?.exist === false, r1);

  const r2 = await authPOST('/internal/user/checkExist', { nickName: longStr });
  // 超长 nickName 走 gRPC 模糊查询，可能触发异常
  assert('§8.超长nickName(500) - 不崩溃',
    r2.success === true || r2.success === false, r2);
}

async function test_09_notExist() {
  console.log('\n🚫 §9. 不存在/异常数据');

  // 格式不合法的邮箱
  const badEmails = ['notanemail', '@', 'a@', '@b.com', 'a@b', '   @   .   '];
  for (const email of badEmails) {
    const r = await authPOST('/internal/user/checkExist', { email });
    assert(`§9.非法邮箱 "${email}" - 不报500`,
      r.success === true || (r.code && r.code !== 500), r);
  }

  // unicode / emoji（gRPC 模糊查询可能对特殊 unicode 抛异常，try-catch 兜底）
  const r1 = await authPOST('/internal/user/checkExist', { nickName: '🎉🎊' });
  assert('§9.emoji花名 - 不崩溃',
    r1.success === true || r1.success === false, r1);

  const r2 = await authPOST('/internal/user/checkExist', { nickName: '日本語テスト' });
  assert('§9.日文花名 - 不崩溃',
    r2.success === true || r2.success === false, r2);

  // 数字花名
  const r3 = await authPOST('/internal/user/checkExist', { nickName: '12345' });
  assert('§9.数字花名 - 不崩溃',
    r3.success === true || r3.success === false, r3);
}

async function test_10_concurrency() {
  console.log('\n🔀 §10. 并发请求');

  const promises = Array.from({ length: 10 }, () =>
    authPOST('/internal/user/checkExist', { email: CONFIG.existUser.email })
  );
  const results = await Promise.all(promises);
  const allOk = results.every(r => r.success === true);
  assert('§10.10个并发请求都成功', allOk);

  const allExist = results.every(r => r.data?.exist === true);
  assert('§10.10个并发结果一致(exist=true)', allExist);

  const allSameName = results.every(r => r.data?.nickName === results[0].data?.nickName);
  assert('§10.10个并发返回nickName一致', allSameName);
}

async function test_11_errorCode() {
  console.log('\n🔢 §11. 错误码规范');

  // 无 token → 错误码不应是 500
  const r1 = await POST('/internal/user/checkExist', { email: CONFIG.existUser.email });
  assert('§11.无token - code非500', r1.code !== 500, r1.code);

  // 参数为空 → 错误码不应是 500
  const r2 = await authPOST('/internal/user/checkExist', {});
  assert('§11.空参数 - code非500', r2.code !== 500, r2.code);

  // 正常请求不存在用户 → success=true, exist=false
  const r3 = await authPOST('/internal/user/checkExist', { email: CONFIG.fakeUser.email });
  assert('§11.不存在用户 - success=true（查询本身成功）', r3.success === true, r3);
  assert('§11.不存在用户 - exist=false', r3.data?.exist === false, r3.data);
}

async function test_12_noLogin() {
  console.log('\n🔓 §12. 免登录验证（requiredLogin=false）');

  // 不带任何 cookie/session，只带 token → 应该能正常调用
  const r1 = await authPOST('/internal/user/checkExist', { email: CONFIG.existUser.email });
  assert('§12.无session+有token - success=true', r1.success === true, r1);
  assert('§12.无session+有token - exist=true', r1.data?.exist === true, r1.data);

  // 带错误 session + 正确 token → 也应该能正常调用
  const r2 = await POST('/internal/user/checkExist', { email: CONFIG.existUser.email }, {
    'X-Internal-Token': CONFIG.internalToken,
    'Cookie': 'SESSION=invalid-session-id',
  });
  assert('§12.错误session+有token - success=true', r2.success === true, r2);
}

async function test_13_badRequest() {
  console.log('\n💥 §13. 请求体异常');

  // 空 body
  const r1 = await fetch(`${CONFIG.host}/api/v1/internal/user/checkExist`, {
    method: 'POST',
    headers: {
      'content-type': 'application/json',
      'X-Internal-Token': CONFIG.internalToken,
    },
    body: '',
  });
  assert('§13.空body - 不报500', r1.status !== 500, r1.status);

  // 非 JSON body
  const r2 = await fetch(`${CONFIG.host}/api/v1/internal/user/checkExist`, {
    method: 'POST',
    headers: {
      'content-type': 'application/json',
      'X-Internal-Token': CONFIG.internalToken,
    },
    body: 'not json',
  });
  assert('§13.非JSON body - 不报500', r2.status !== 500, r2.status);

  // content-type 不是 json
  const r3 = await fetch(`${CONFIG.host}/api/v1/internal/user/checkExist`, {
    method: 'POST',
    headers: {
      'content-type': 'text/plain',
      'X-Internal-Token': CONFIG.internalToken,
    },
    body: JSON.stringify({ email: CONFIG.existUser.email }),
  });
  assert('§13.content-type=text/plain - 不报500', r3.status !== 500, r3.status);

  // GET 方法（接口只支持 POST）
  const r4 = await fetch(`${CONFIG.host}/api/v1/internal/user/checkExist`, {
    method: 'GET',
    headers: { 'X-Internal-Token': CONFIG.internalToken },
  });
  assert('§13.GET方法 - 不报500', r4.status !== 500, r4.status);
}

